const geminiOutput = $input.all()[0].json;

// Get the text from Gemini parts
const parts = geminiOutput.content?.parts || geminiOutput.parts || [];
let text = parts[0]?.text || geminiOutput.text || "";

// Clean markdown
text = text.replace(/```json/g, '').replace(/```/g, '').trim();

// Try to find JSON in the text
const jsonMatch = text.match(/\{[\s\S]*\}/);
let ai = { risk_level: "MEDIUM", reason: "Foreign country access detected" };

if (jsonMatch) {
  try {
    ai = JSON.parse(jsonMatch[0]);
  } catch(e) {
    // keep default
  }
}

const prevData = $('Fraud Rules Engine').first().json;

return [{
  json: {
    ...prevData,
    ai_risk_level: ai.risk_level || "MEDIUM",
    ai_reason: ai.reason || "Suspicious activity detected",
    raw_ai_response: text
  }
}];

